queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?election_type ?start_date WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasElections ?child ; p:hasPolitical_Reporters ?parent . } GROUP BY ?child }
  ?child p:election_type ?election_type .
  ?child p:start_date ?start_date .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Political_Reporters } }
  FILTER(?nf = ?total)
}

